    15→import type { Project, SemanticRelease } from "@/lib/api/types";
    16→
    17→/* ---------- Urgency chip ---------- */
    18→
    19→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    20→  critical: { bg: "#dc2626", text: "#ffffff" },
    21→  high: { bg: "#f97316", text: "#ffffff" },
    22→  medium: { bg: "#f59e0b", text: "#ffffff" },
    23→  low: { bg: "#6b7280", text: "#ffffff" },
    24→};
    25→
    26→function UrgencyChip({ urgency }: { urgency: string }) {
    27→  const u = urgency.toLowerCase();
    28→  const style = URGENCY_COLORS[u];
    29→  if (!style) return null;
    30→  return (
    31→    <span
    32→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    33→      style={{ backgroundColor: style.bg, color: style.text }}
    34→    >
    35→      {urgency}
    36→    </span>
    37→  );
    38→}
    39→
    40→/* ---------- Helpers ---------- */
    41→
    42→const PER_PAGE = 15;
    43→
    44→/* ---------- Main component ---------- */
    45→
    46→export function SemanticReleasesList() {
    47→  return (
    48→    <Suspense>
    49→      <SemanticReleasesListInner />
    50→    </Suspense>
    51→  );
    52→}
    53→
    54→function SemanticReleasesListInner() {
    55→  const searchParams = useSearchParams();
    56→  const initialProject = searchParams.get("project") ?? "all";
    57→  const [page, setPage] = useState(1);
    58→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    59→  const [deletingId, setDeletingId] = useState<string | null>(null);
    60→
    61→  /* Fetch projects for the filter dropdown */
    62→  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    63→    projectsApi.list(1, 100)
    64→  );
    65→
    66→  /* Fetch semantic releases — scoped by project or all */
    67→  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    68→    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    69→    () => srApi.list(projectFilter, page, PER_PAGE)
    70→  );
    71→
    72→  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    73→    projectFilter === "all" ? ["sr-all", page] : null,
    74→    () => srApi.listAll(page, PER_PAGE)
    75→  );
    76→
    77→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    78→  const releases: SemanticRelease[] =
    79→    projectFilter !== "all"
    80→      ? scopedData?.data ?? []
    81→      : allData?.data ?? [];
    82→
    83→  const mutateData = projectFilter !== "all" ? mutateScopedData : mutateAllData;
    84→
    85→  /* Pagination math */
    86→  const activeData = projectFilter !== "all" ? scopedData : allData;
    87→  const total = activeData?.meta?.total ?? 0;
    88→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    89→  const startRow = (page - 1) * PER_PAGE + 1;
    90→  const endRow = Math.min(page * PER_PAGE, total);
    91→
    92→  return (
    93→    <div className="space-y-6 fade-in">
    94→      {/* Page title */}
    95→      <h1
    96→        style={{
    97→          fontFamily: "var(--font-fraunces)",
    98→          fontSize: "24px",
    99→          fontWeight: 700,
   100→          color: "#111113",
   101→        }}
   102→      >
   103→        Semantic Releases
   104→      </h1>
   105→
   106→      {/* Project filter */}
   107→      <div>
   108→        <select
   109→          value={projectFilter}
   110→          onChange={(e) => {
   111→            setProjectFilter(e.target.value);
   112→            setPage(1);
   113→          }}
   114→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   115→          style={{
   116→            fontFamily: "var(--font-dm-sans)",
   117→            fontSize: "13px",
   118→            color: "#111113",
   119→            border: "1px solid #e8e8e5",
   120→          }}
   121→          onFocus={(e) =>
   122→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   123→          }
   124→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   125→        >
   126→          <option value="all">All Projects</option>
   127→          {projectsData?.data.map((p: Project) => (
   128→            <option key={p.id} value={p.id}>
   129→              {p.name}
   130→            </option>
   131→          ))}
   132→        </select>
   133→      </div>
   134→
   135→      {/* Table card */}
   136→      <div
   137→        className="overflow-hidden rounded-lg bg-white"
   138→        style={{ border: "1px solid #e8e8e5" }}
   139→      >
   140→        {isLoading ? (
   141→          <div
   142→            className="py-16 text-center"
   143→            style={{
   144→              fontFamily: "var(--font-dm-sans)",
   145→              fontSize: "13px",
   146→              color: "#6b7280",
   147→            }}
   148→          >
   149→            Loading...
   150→          </div>
   151→        ) : releases.length === 0 ? (
   152→          <div className="py-16 text-center">
   153→            <p
   154→              style={{
   155→                fontFamily: "var(--font-fraunces)",
   156→                fontStyle: "italic",
   157→                fontSize: "15px",
   158→                color: "#9ca3af",
   159→              }}
   160→            >
   161→              No semantic releases yet
   162→            </p>
   163→          </div>
   164→        ) : (
   165→          <table className="w-full">
   166→            <thead>
   167→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   168→                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   169→                  (col) => (
   170→                    <th
   171→                      key={col}
   172→                      className="px-4 py-3 text-left"
   173→                      style={{
   174→                        fontFamily: "var(--font-dm-sans)",
   175→                        fontSize: "11px",
   176→                        fontWeight: 600,
   177→                        textTransform: "uppercase" as const,
   178→                        letterSpacing: "0.08em",
   179→                        color: "#9ca3af",
   180→                      }}
   181→                    >
   182→                      {col}
   183→                    </th>
   184→                  )
   185→                )}
   186→              </tr>
   187→            </thead>
   188→            <tbody>
   189→              {releases.map((sr) => {
   190→                return (
   191→                  <tr
   192→                    key={sr.id}
   193→                    className="transition-colors hover:bg-[#fafaf9]"
   194→                    style={{ borderBottom: "1px solid #e8e8e5" }}
   195→                  >
   196→                    {/* Project */}
   197→                    <td className="px-4 py-3">
   198→                      {sr.project_name ? (
   199→                        <Link
   200→                          href={`/projects/${sr.project_id}`}
   201→                          className="hover:underline"
   202→                          style={{
   203→                            fontFamily: "var(--font-dm-sans)",
   204→                            fontSize: "13px",
   205→                            color: "#111113",
   206→                            fontWeight: 500,
   207→                          }}
   208→                        >
   209→                          {sr.project_name}
   210→                        </Link>
   211→                      ) : (
   212→                        <span
   213→                          style={{
   214→                            fontFamily: "var(--font-dm-sans)",
   215→                            fontSize: "13px",
   216→                            color: "#9ca3af",
   217→                          }}
   218→                        >
   219→                          {"\u2014"}
   220→                        </span>
   221→                      )}
   222→                    </td>
   223→
   224→                    {/* Version */}
   225→                    <td className="px-4 py-3">
   226→                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
   227→                        <VersionChip version={sr.version} />
   228→                      </Link>
   229→                    </td>
   230→
   231→                    {/* Status */}
   232→                    <td className="px-4 py-3">
   233→                      <span
   234→                        className="text-[13px] font-medium"
   235→                        style={{
   236→                          fontFamily: "var(--font-dm-sans)",
   237→                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
   238→                        }}
   239→                      >
   240→                        {sr.status}
   241→                      </span>
   242→                    </td>
   243→
   244→                    {/* Urgency */}
   245→                    <td className="px-4 py-3">
   246→                      {sr.report?.urgency ? (
   247→                        <UrgencyChip urgency={sr.report.urgency} />
   248→                      ) : (
   249→                        <span
   250→                          style={{
   251→                            fontFamily: "var(--font-dm-sans)",
   252→                            fontSize: "13px",
   253→                            color: "#9ca3af",
   254→                          }}
   255→                        >
   256→                          {"\u2014"}
   257→                        </span>
   258→                      )}
   259→                    </td>
   260→
   261→                    {/* Age */}
   262→                    <td className="px-4 py-3">
   263→                      <span
   264→                        style={{
   265→                          fontFamily: "var(--font-dm-sans)",
   266→                          fontSize: "13px",
   267→                          color: "#9ca3af",
   268→                        }}
   269→                      >
   270→                        {timeAgo(sr.completed_at ?? sr.created_at)}
   271→                      </span>
   272→                    </td>
   273→
   274→                    {/* Delete */}
   275→                    <td className="px-4 py-3">
   276→                      <button
   277→                        onClick={() => setDeletingId(sr.id)}
   278→                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
   279→                        style={{ color: "#9ca3af" }}
   280→                        title="Delete semantic release"
   281→                      >
   282→                        <Trash2 className="h-4 w-4" />
   283→                      </button>
   284→                    </td>
   285→                  </tr>
   286→                );
   287→              })}
   288→            </tbody>
   289→          </table>
   290→        )}
   291→      </div>
   292→
   293→      {/* Pagination */}
   294→      {total > 0 && (
   295→        <div className="flex items-center justify-between">
   296→          <span
   297→            style={{
   298→              fontFamily: "var(--font-dm-sans)",
   299→              fontSize: "13px",
   300→              color: "#9ca3af",
   301→            }}
   302→          >
   303→            {startRow}&ndash;{endRow} of {total}
   304→          </span>
   305→          <div className="flex items-center gap-2">
   306→            <button
   307→              disabled={page <= 1}
   308→              onClick={() => setPage(page - 1)}
   309→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   310→              style={{
   311→                fontFamily: "var(--font-dm-sans)",
   312→                fontSize: "13px",
   313→                color: "#374151",
   314→                border: "1px solid #e8e8e5",
   315→              }}
   316→            >
   317→              Previous
   318→            </button>
   319→            <button
   320→              disabled={page >= totalPages}
   321→              onClick={() => setPage(page + 1)}
   322→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   323→              style={{
   324→                fontFamily: "var(--font-dm-sans)",
   325→                fontSize: "13px",
   326→                color: "#374151",
   327→                border: "1px solid #e8e8e5",
   328→              }}
   329→            >
   330→              Next
   331→            </button>
   332→          </div>
   333→        </div>
   334→      )}
   335→
   336→      {/* Delete confirmation */}
   337→      <ConfirmDialog
   338→        open={!!deletingId}
   339→        onOpenChange={(open) => {
   340→          if (!open) setDeletingId(null);
   341→        }}
   342→        title="Delete Semantic Release"
   343→        description="This will permanently delete this semantic release and its report."
   344→        onConfirm={async () => {
   345→          if (deletingId) {
   346→            await srApi.delete(deletingId);
   347→            mutateData();
   348→          }
   349→        }}
   350→      />
   351→    </div>
   352→  );
   353→}
