    22→  Copy,
    23→  ShieldAlert,
    24→  BookOpen,
    25→  Download,
    26→} from "lucide-react";
    27→
    28→function getRiskColors(riskLevel?: string) {
    29→  switch (riskLevel?.toUpperCase()) {
    30→    case "CRITICAL":
    31→      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    32→    case "HIGH":
    33→      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    34→    case "MEDIUM":
    35→      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    36→    case "LOW":
    37→    default:
    38→      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    39→  }
    40→}
    41→
    42→function safeHostname(url: string): string {
    43→  try {
    44→    return new URL(url).hostname.replace("www.", "");
    45→  } catch {
    46→    return url;
    47→  }
    48→}
    49→
    50→function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
    51→  const lower = url.toLowerCase();
    52→  const filename = lower.split("/").pop() ?? "";
    53→
    54→  // Detect platform from common patterns in the URL or filename
    55→  const platforms: [RegExp, string][] = [
    56→    [/linux.*amd64|amd64.*linux/, "Linux x64"],
    57→    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
    58→    [/linux.*386|linux.*i386/, "Linux x86"],
    59→    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
    60→    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
    61→    [/darwin|macos|osx/, "macOS"],
    62→    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
    63→    [/windows.*386|win32/, "Windows x86"],
    64→    [/windows/, "Windows"],
    65→  ];
    66→
    67→  // Check if this is a direct binary (archive or executable)
    68→  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
    69→
    70→  if (isArchive) {
    71→    for (const [pattern, label] of platforms) {
    72→      if (pattern.test(filename) || pattern.test(url)) {
    73→        return { label, isDirect: true };
    74→      }
    75→    }
    76→    // Direct download but platform unknown — use filename
    77→    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
    78→    return { label: cleanName || safeHostname(url), isDirect: true };
    79→  }
    80→
    81→  // Not a direct binary — generic link
    82→  return { label: safeHostname(url), isDirect: false };
    83→}
    84→
    85→export function SemanticReleaseDetail() {
    86→  // Read IDs from URL path — useParams() returns stale "0" in static export
    87→  const projectId = getPathSegment(1); // /projects/{id}/semantic-releases/{srId}
    88→  const srId = getPathSegment(3);
    89→  const router = useRouter();
    90→  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    91→  const { data: projectData } = useSWR(`project-${projectId}`, () =>
    92→    projectsApi.get(projectId),
    93→  );
    94→  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
    95→    srApi.getSources(srId),
    96→  );
    97→  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
    98→    sourcesApi.listByProject(projectId),
    99→  );
   100→  const { data: contextSourcesData } = useSWR(
   101→    `project-context-sources-${projectId}`,
   102→    () => contextSources.list(projectId),
   103→  );
   104→
   105→  if (isLoading) {
   106→    return (
   107→      <div className="flex justify-center py-20">
   108→        <div
   109→          className="text-[13px] text-[#9ca3af]"
   110→          style={{ fontFamily: "var(--font-dm-sans)" }}
   111→        >
   112→          Loading...
   113→        </div>
   114→      </div>
   115→    );
   116→  }
   117→
   118→  const sr = data?.data;
   119→  if (!sr) {
   120→    return (
   121→      <div className="flex justify-center py-20">
   122→        <div
   123→          className="text-[13px] text-[#9ca3af]"
   124→          style={{ fontFamily: "var(--font-dm-sans)" }}
   125→        >
   126→          Semantic release not found
   127→        </div>
   128→      </div>
   129→    );
   130→  }
   131→
   132→  const project = projectData?.data;
   133→  const releasesList = srSourcesData?.data ?? [];
   134→  const sourcesList = sourcesData?.data ?? [];
   135→  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   136→  const contextSourcesList = contextSourcesData?.data ?? [];
   137→
   138→  const handleDelete = async () => {
   139→    if (!confirm("Delete this semantic release?")) return;
   140→    try {
   141→      await srApi.delete(srId);
   142→      router.push("/semantic-releases");
   143→    } catch {
   144→      alert("Failed to delete semantic release.");
   145→    }
   146→  };
   147→
   148→  const report = sr.report;
   149→  const riskLevel = report?.risk_level?.toUpperCase();
   150→  const hasRiskOrUrgency = riskLevel || report?.urgency;
   151→  const riskColors = getRiskColors(riskLevel);
   152→
   153→  const statusChecks = report?.status_checks ?? [];
   154→  const downloadLinks = report?.download_links ?? [];
   155→  const downloadCommands = report?.download_commands ?? [];
   156→  const hasAvailabilitySection =
   157→    statusChecks.length > 0 ||
   158→    downloadLinks.length > 0 ||
   159→    downloadCommands.length > 0;
   160→
   161→  return (
   162→    <div className="fade-in mx-auto max-w-[760px]">
   163→      {/* 1. Back link */}
   164→      <Link
   165→        href="/semantic-releases"
   166→        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   167→        style={{
   168→          fontFamily: "var(--font-dm-sans)",
   169→          fontSize: "13px",
   170→          color: "#6b7280",
   171→        }}
   172→      >
   173→        <ArrowLeft size={14} />
   174→        Back to Semantic Releases
   175→      </Link>
   176→
   177→      {/* 2. Project byline */}
   178→      {project?.name && (
   179→        <p
   180→          className="mb-1 text-[13px] italic text-[#9ca3af]"
   181→          style={{ fontFamily: "var(--font-fraunces)" }}
   182→        >
   183→          {project.name}
   184→        </p>
   185→      )}
   186→
   187→      {/* 3. Version heading */}
   188→      <h1
   189→        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
   190→        style={{ fontFamily: "var(--font-fraunces)" }}
   191→      >
   192→        {sr.version}
   193→      </h1>
   194→
   195→      {/* 4. Subject line */}
   196→      {report?.subject && (
   197→        <p
   198→          className="mt-2 text-[20px] leading-[1.4] text-[#374151]"
   199→          style={{ fontFamily: "var(--font-dm-sans)" }}
