   180→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   181→	var cfg slackConfig
   182→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   183→		return fmt.Errorf("parse slack config: %w", err)
   184→	}
   185→
   186→	// Try to parse body as a SemanticReport for rich formatting.
   187→	var blocks []slackBlock
   188→	var report models.SemanticReport
   189→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   190→		blocks = buildSemanticBlocks(msg.Title, &report, msg)
   191→	} else {
   192→		// Fallback: extract known fields from raw data for a readable message.
   193→		blocks = []slackBlock{
   194→			{Type: "header", Text: &slackText{Type: "plain_text", Text: msg.Title}},
   195→		}
   196→		if fields, ok := parseRawBody(msg.Body); ok {
   197→			if fields.Changelog != "" {
   198→				blocks = append(blocks, slackBlock{
   199→					Type: "section",
   200→					Text: &slackText{Type: "mrkdwn", Text: fields.Changelog},
   201→				})
   202→			}
   203→		} else {
   204→			blocks = append(blocks, slackBlock{
   205→				Type: "section",
   206→				Text: &slackText{Type: "mrkdwn", Text: msg.Body},
   207→			})
   208→		}
   209→
   210→		// Add source info and links
   211→		var linkParts []string
   212→		if msg.Provider != "" && msg.Repository != "" {
   213→			linkParts = append(linkParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   214→		}
   215→		if msg.SourceURL != "" {
   216→			linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   217→		}
   218→		if msg.ReleaseURL != "" {
   219→			linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   220→		}
   221→		if len(linkParts) > 0 {
   222→			blocks = append(blocks, slackBlock{
   223→				Type: "context",
   224→				Elements: []slackText{
   225→					{Type: "mrkdwn", Text: strings.Join(linkParts, "  |  ")},
   226→				},
   227→			})
   228→		}
   229→	}
   230→
   231→	payload := slackPayload{Blocks: blocks}
   232→
   233→	body, err := json.Marshal(payload)
   234→	if err != nil {
   235→		return fmt.Errorf("marshal slack payload: %w", err)
   236→	}
   237→
   238→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   239→	if err != nil {
   240→		return fmt.Errorf("create request: %w", err)
   241→	}
   242→	req.Header.Set("Content-Type", "application/json")
   243→
   244→	client := s.Client
   245→	if client == nil {
   246→		client = http.DefaultClient
   247→	}
   248→
   249→	resp, err := client.Do(req)
   250→	if err != nil {
   251→		return fmt.Errorf("send slack notification: %w", err)
   252→	}
   253→	defer resp.Body.Close()
   254→
   255→	if resp.StatusCode >= 400 {
   256→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
   257→	}
   258→	return nil
   259→}
