    14→// discordEmbedDescriptionLimit is Discord's maximum embed description length.
    15→const discordEmbedDescriptionLimit = 4096
    16→
    17→type discordConfig struct {
    18→	WebhookURL string `json:"webhook_url"`
    19→}
    20→
    21→// DiscordSender sends notifications as Discord webhook messages with embeds.
